import primer3
def read_fasta(path):
    recs={}; name=None
    for line in open(path):
        line=line.strip()
        if line.startswith('>'):
            name=line[1:]; recs[name]=[]
        elif line:
            recs[name].append(line)
    return {k:''.join(v).upper() for k,v in recs.items()}
r=read_fasta('/app/sequences.fasta')
inp=r['input']; out=r['output']
p=215
comp={'A':'T','T':'A','G':'C','C':'G'}
def rc(s): return ''.join(comp[c] for c in reversed(s))
UP=inp[:p]      # top strand 5' of insertion, ends ...CATATGAG
DOWN=inp[p:]    # top strand 3' of insertion, starts CAAGGGC
INS='TAGATTAGAAGAAGAATTAAGAAGAAGATTAACAGAAAG'
assert out== UP+INS+DOWN
def tm(s):
    return primer3.calc_tm(s, mv_conc=50, dv_conc=2, dntp_conc=0.8, dna_conc=500,
                           tm_method='santalucia', salt_corrections_method='santalucia')
# Forward anneals to DOWN (top strand): inp[p:p+L]
# Reverse anneals to UP: revcomp(inp[p-L:p])
print("FWD anneal candidates (DOWN):")
for L in range(15,46):
    seq=DOWN[:L]
    print(L, round(tm(seq),2), seq)
print("\nREV anneal candidates (revcomp of UP end):")
for L in range(15,46):
    seq=rc(UP[-L:])
    print(L, round(tm(seq),2), seq)
